VALUES
  ('medical-tech-moex-02208', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '關  於核酸的敘述，下列何者最不適當？', '["可  以用鹼性溶解法（alkaline lysis methods）處理Gram-negative bacteria來將核酸釋出", "從  檢體中執行核酸萃取，只能萃取出DNA或是RNA的其中一種", "萃  取出的RNA較不穩定，最好是保存在-70℃，並儘快執行後續分析", "可  以使用紫外分光光度計，測定260 nm吸光度並換算為核酸量"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:07+00:00", "source_pdf_sha1": "c376b2134086", "answer_pdf_sha1": "8ae5d9680e26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114090", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 47, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02209', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '關  於巢式聚合酶連鎖反應（nested PCR）的敘述，下列何者最不適當？', '["是  將第一次PCR反應的產物作為第二次PCR反應的模板", "需  設計兩組引子（primer）", "通  常在模板DNA含量較高時使用", "所  使用的第二組引子（primer）會結合在第一次PCR產物的內部"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:07+00:00", "source_pdf_sha1": "c376b2134086", "answer_pdf_sha1": "8ae5d9680e26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114090", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 48, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02210', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '如  圖為genomic DNA經過bisulfite conversion後，利用圖中所示探針進行MethyLight分析所得之擴增曲 線，下列敘述何者最不適當？', '["此  區域中有4個CpG位點", "可  用於檢測腫瘤檢體中抑癌基因啟動子區域是否有高度甲基化的現象", "a 曲線是基因啟動子區域沒有甲基化的結果", "可  選用富含CpG位點的Alu elements來作為DNA input control"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:07+00:00", "source_pdf_sha1": "c376b2134086", "answer_pdf_sha1": "8ae5d9680e26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114090", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 49, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02211', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '下  列那個限制酶的切割作用會受CpG甲基化的影響？', '["M spI", "H paII", "K pnI", "N deI"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:07+00:00", "source_pdf_sha1": "c376b2134086", "answer_pdf_sha1": "8ae5d9680e26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114090", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 50, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02212', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '下  列何種情況最不適合使用次世代定序技術來進行檢測？', '["多  基因造成的遺傳疾病", "人  類白血球抗原分型", "已  知家族遺傳突變位點的單基因遺傳疾病", "計  算腫瘤突變量來評估是否適用免疫檢查點抑制劑"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:07+00:00", "source_pdf_sha1": "c376b2134086", "answer_pdf_sha1": "8ae5d9680e26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114090", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 51, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02213', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '針  對單一核苷酸多型性（single nucleotide polymorphism, SNP）或單一核苷酸變異（single nucleotide variation, SNV）晶片的臨床檢驗應用，下列敘述何者最不適當？', '["可  用於已知HLA相關藥物基因體檢測", "可  以檢驗受試者具有特定疾病的發生風險", "可  用於抗藥性病原體的檢驗", "可  以篩檢新穎（novel）單一核苷酸變異位點"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:07+00:00", "source_pdf_sha1": "c376b2134086", "answer_pdf_sha1": "8ae5d9680e26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114090", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 52, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02214', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '序  列特異聚合酶連鎖反應（polymerase chain reaction-seguence-specific primers, PCR-SSP）是基於 sequence-specific primers進行多樣性基因分型，下列敘述何者最不適當？', '["臨  床上可用在 human leukocyte antigen（HLA）typing", "使  用的Taq DNA polymerase，需要有3''端至5''端exonuclease活性", "操  作時，需有增幅內生性對照組（internal control）", "反  應完後，需要進行電泳分析"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:07+00:00", "source_pdf_sha1": "c376b2134086", "answer_pdf_sha1": "8ae5d9680e26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114090", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 53, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02215', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '下  列何種等位基因特異性檢驗方法，需要在基因放大且經限制酶切割後，再進行膠體電泳分析？', '["a mplification refractory mutation system（ARMS）", "m utagenically separated PCR（MS-PCR）", "c hemical cleavage of mismatch duplexes（CCM）", "a mplified created restriction sites（ACRS）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:07+00:00", "source_pdf_sha1": "c376b2134086", "answer_pdf_sha1": "8ae5d9680e26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114090", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 54, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02216', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '原  位螢光雜交法（FISH）是利用螢光探針偵測細胞內特定之DNA序列，下列敘述何者最不適當？', '["進  行interphase FISH時，所使用的probe長度建議為60～200 kb", "使  用全染色體探針時，建議進行interphase FISH", "偵  測translocation時，可設計兩條probes進行檢測", "進  行metaphase FISH時，需加入colcemides，使細胞停在metaphase"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:07+00:00", "source_pdf_sha1": "c376b2134086", "answer_pdf_sha1": "8ae5d9680e26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114090", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 55, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02217', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '在  比較配對檢體之蛋白質的差別，下列何種分離方法可以最有效減少操作過程的誤差？', '["二  維電泳分析（2D-PAGE）", "磁  珠親和分離法（Beadbased affinity fractionation）", "螢  光染劑標示二維凝膠電泳（fluorescent two dimensional difference in-gel electrophoresis, fluorescent 2D-DIGE）", "膠  體過濾層析法（gel filtration chromatography）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:07+00:00", "source_pdf_sha1": "c376b2134086", "answer_pdf_sha1": "8ae5d9680e26", "source_family": "moex-gov-tw", "moex": {"exam_code": "114090", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 56, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
